#usda 1.0
(
    defaultPrim = "Shot"
    subLayers = [
        @assets.usda@
    ]
)

def Xform "Shot"
{
    def Xform "Set"
    {
        def Xform "ChairA"
        {
            double3 xformOp:translate = (-2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]

            def Mesh "Geo"
            {
                int[] faceVertexCounts = [3, 3, 3, 3, 3, 3, 3, 3, 3, 3, 3, 3]
                int[] faceVertexIndices = [0, 1, 2, 2, 3, 0, 0, 4, 1, 4, 5, 1, 1, 5, 6, 6, 2, 1, 7, 6, 5, 5, 4, 7, 7, 4, 0, 0, 3, 7, 6, 7, 3, 6, 3, 2]
                point3f[] points = [(-0.5, 0, -0.5), (0.5, 0, -0.5), (0.5, 1, -0.5), (-0.5, 1, -0.5), (-0.5, 0, 0.5), (0.5, 0, 0.5), (0.5, 1, 0.5), (-0.5, 1, 0.5)]
            }
        }

        def Xform "ChairB"
        {
            double3 xformOp:translate = (2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]

            def Mesh "Geo"
            {
                int[] faceVertexCounts = [3, 3, 3, 3, 3, 3, 3, 3, 3, 3, 3, 3]
                int[] faceVertexIndices = [0, 1, 2, 2, 3, 0, 0, 4, 1, 4, 5, 1, 1, 5, 6, 6, 2, 1, 7, 6, 5, 5, 4, 7, 7, 4, 0, 0, 3, 7, 6, 7, 3, 6, 3, 2]
                point3f[] points = [(-0.5, 0, -0.5), (0.5, 0, -0.5), (0.5, 1, -0.5), (-0.5, 1, -0.5), (-0.5, 0, 0.5), (0.5, 0, 0.5), (0.5, 1, 0.5), (-0.5, 1, 0.5)]
            }
        }
    }

    def Xform "Lighting" (
        variants = {
            string lightingVariant = "night"
        }
        prepend variantSets = "lightingVariant"
    )
    {
        def SphereLight "Sun"
        {
            float inputs:intensity = 50000
        }

        def DomeLight "Sky"
        {
            float inputs:intensity = 500
        }
    }
}

